#include <bits/stdc++.h>
using namespace std;
int main(){
    int m=0,t,b=0;
    for(int i=1;i<=12;i++){
        cin>>t;
        m+=300;
        m-=t;
        if(m<0){
            cout<<-i;
            return 0;
        }
        if(m>=100){
            b+=m-m%100;
            m%=100;
        }
    }
    cout<<m+b+b/5;
    return 0;
}
